#!/usr/bin/env node
/**
 * gen-hook-docs.mjs - Auto-generate per-hook documentation pages.
 *
 * Walks packages/hooks/src/*\/index.ts, dynamically imports each hook's
 * compiled module from packages/hooks/dist/<name>/index.js, reads its
 * manifest, and writes docs/hooks/<name>.md.
 *
 * Behavior description and notes are sourced from a doc-block comment
 * in the source (lines starting with `// DOC:` or `// NOTES:`). Anything
 * not present is left as a TODO for hand-curation.
 *
 * Footer marks each file as auto-generated.
 *
 * Usage: node scripts/gen-hook-docs.mjs
 */

import { readdirSync, readFileSync, writeFileSync, mkdirSync, existsSync } from 'node:fs';
import { fileURLToPath, pathToFileURL } from 'node:url';
import { dirname, join, resolve } from 'node:path';

const __dirname = dirname(fileURLToPath(import.meta.url));
const REPO_ROOT = resolve(__dirname, '..');
const SRC_DIR = join(REPO_ROOT, 'packages/hooks/src');
const DIST_DIR = join(REPO_ROOT, 'packages/hooks/dist');
const OUT_DIR = join(REPO_ROOT, 'docs/hooks');

function readDocBlock(srcPath) {
  if (!existsSync(srcPath)) return { description: null, notes: null };
  const text = readFileSync(srcPath, 'utf8');
  const descMatch = text.match(/\/\/\s*DOC:\s*([\s\S]*?)(?:\n[^/]|\nimport|\nconst |\nexport)/);
  const notesMatch = text.match(/\/\/\s*NOTES:\s*([\s\S]*?)(?:\n[^/]|\nimport|\nconst |\nexport)/);
  const cleanLines = (s) =>
    s
      .split('\n')
      .map((l) => l.replace(/^\s*\/\/\s?/, '').trim())
      .filter((l) => l.length > 0)
      .join(' ');
  return {
    description: descMatch ? cleanLines(descMatch[1]) : null,
    notes: notesMatch ? cleanLines(notesMatch[1]) : null,
  };
}

function severityCell(severity) {
  if (typeof severity === 'string') return severity;
  if (severity && typeof severity === 'object') {
    return Object.entries(severity)
      .map(([profile, sev]) => `${profile}=${sev}`)
      .join(', ');
  }
  return String(severity);
}

function buildPage(manifest, doc) {
  const description =
    doc.description ??
    'TODO: hand-curated behavior description. Auto-generator only emits manifest fields.';
  const notes =
    doc.notes ??
    'TODO: hand-curated notes / known limitations. See docs/known-bypasses.md for cross-cutting gaps.';

  const matchers = manifest.matchers && manifest.matchers.length > 0
    ? manifest.matchers.map((m) => `\`${m}\``).join(', ')
    : '(none)';
  const profiles = manifest.profiles.join(', ');
  const sevLabel = severityCell(manifest.severity);

  return `# ${manifest.name}

> Auto-generated from \`packages/hooks/src/${manifest.name}/index.ts\` manifest. Do not hand-edit. Run \`pnpm gen:hook-docs\` to regenerate.

## Manifest

| Field | Value |
| --- | --- |
| Event | \`${manifest.event}\` |
| Matchers | ${matchers} |
| Threat | [\`${manifest.threat}\`](../threat-model.md) |
| Profiles | ${profiles} |
| Severity | ${sevLabel} |
| Timeout | ${manifest.timeout_ms} ms |

## Behavior

${description}

## Threat coverage

This hook contributes to mitigation of threat \`${manifest.threat}\`. See [\`docs/threat-model.md\`](../threat-model.md) for the full register and mitigation chain.

## Notes / known limitations

${notes}

For cross-cutting detection gaps (heredoc bodies, hardlink aliasing, alias-wrapped git, pipe-to-interpreter, etc.) see [\`docs/known-bypasses.md\`](../known-bypasses.md).

---

_Generated by \`scripts/gen-hook-docs.mjs\` from the hook manifest. Hand-curated behavior + notes are sourced from \`// DOC:\` and \`// NOTES:\` comment blocks in the hook source._
`;
}

async function main() {
  if (!existsSync(OUT_DIR)) mkdirSync(OUT_DIR, { recursive: true });

  const hookDirs = readdirSync(SRC_DIR, { withFileTypes: true })
    .filter((e) => e.isDirectory())
    .map((e) => e.name)
    .sort();

  let written = 0;
  const failures = [];

  for (const name of hookDirs) {
    const distEntry = join(DIST_DIR, name, 'index.js');
    if (!existsSync(distEntry)) {
      failures.push(`${name}: missing dist entry at ${distEntry} (run pnpm build)`);
      continue;
    }
    let mod;
    try {
      mod = await import(pathToFileURL(distEntry).href);
    } catch (err) {
      failures.push(`${name}: import failed: ${err.message}`);
      continue;
    }
    const manifest = mod.default?.manifest;
    if (!manifest) {
      failures.push(`${name}: dist module has no default.manifest`);
      continue;
    }
    const srcPath = join(SRC_DIR, name, 'index.ts');
    const doc = readDocBlock(srcPath);
    const page = buildPage(manifest, doc);
    const outPath = join(OUT_DIR, `${name}.md`);
    writeFileSync(outPath, page);
    written += 1;
    process.stdout.write(`wrote ${outPath}\n`);
  }

  process.stdout.write(`\ngen-hook-docs: ${written} pages written\n`);
  if (failures.length > 0) {
    process.stderr.write(`\nfailures:\n${failures.map((f) => `  - ${f}`).join('\n')}\n`);
    process.exit(1);
  }
}

main().catch((err) => {
  process.stderr.write(`gen-hook-docs failed: ${err.stack ?? err.message}\n`);
  process.exit(1);
});
